'use client';

import { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Brand } from '@/lib/types';
import { mockBrands } from '@/lib/mockData';
import {
  Edit2,
  Trash2,
  Plus,
  X,
  Check,
} from 'lucide-react';

interface EditingBrand extends Brand {
  isNew?: boolean;
}

export function BrandManagement() {
  const [brands, setBrands] = useState<Brand[]>(mockBrands);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBrand, setEditingBrand] = useState<EditingBrand | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredBrands = brands.filter((brand) =>
    brand.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleAddBrand = () => {
    setEditingBrand({
      id: Date.now().toString(),
      name: '',
      logo: '🏛️',
      description: '',
      founded: new Date().getFullYear(),
      country: '',
      createdAt: new Date(),
      isNew: true,
    });
    setIsModalOpen(true);
  };

  const handleEditBrand = (brand: Brand) => {
    setEditingBrand(brand);
    setIsModalOpen(true);
  };

  const handleDeleteBrand = (id: string) => {
    if (confirm('Are you sure you want to delete this brand?')) {
      setBrands(brands.filter((b) => b.id !== id));
    }
  };

  const handleSaveBrand = () => {
    if (!editingBrand) return;

    if (editingBrand.isNew) {
      setBrands([...brands, { ...editingBrand, isNew: undefined }]);
    } else {
      setBrands(brands.map((b) => (b.id === editingBrand.id ? editingBrand : b)));
    }

    setIsModalOpen(false);
    setEditingBrand(null);
  };

  return (
    <div className="space-y-6 p-4 lg:p-8">
      {/* Search and Add Button */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
        <div className="w-full sm:w-96">
          <input
            type="text"
            placeholder="Search brands..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary"
          />
        </div>
        <Button onClick={handleAddBrand} className="flex items-center gap-2">
          <Plus className="w-4 h-4" />
          Add Brand
        </Button>
      </div>

      {/* Brands Grid */}
      <div className="grid grid-cols-1 h-full md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredBrands.map((brand) => (
          <Card key={brand.id} className="p-6 h-full hover:shadow-lg transition-shadow">
            <div className="space-y-4 h-full flex flex-col justify-between">
              <div className="flex items-start justify-between">
                <div className="text-4xl">{brand.logo}</div>
                <div className="flex gap-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleEditBrand(brand)}
                  >
                    <Edit2 className="w-4 h-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleDeleteBrand(brand.id)}
                  >
                    <Trash2 className="w-4 h-4 text-red-500" />
                  </Button>
                </div>
              </div>

              <div>
                <h3 className="text-lg font-semibold text-foreground">
                  {brand.name}
                </h3>
                <p className="text-sm text-muted-foreground mt-1">
                  {brand.description}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-4 border-t border-border">
                <div>
                  <p className="text-xs text-muted-foreground">Founded</p>
                  <p className="font-semibold text-foreground">{brand.founded}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Country</p>
                  <p className="font-semibold text-foreground">{brand.country}</p>
                </div>
              </div>
            </div>
          </Card>
        ))}
      </div>

      {/* Brand Modal */}
      {isModalOpen && editingBrand && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <Card className="w-full max-w-md p-6 space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-2xl font-bold text-foreground">
                {editingBrand.isNew ? 'Add Brand' : 'Edit Brand'}
              </h2>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  setIsModalOpen(false);
                  setEditingBrand(null);
                }}
              >
                <X className="w-5 h-5" />
              </Button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-foreground mb-2">
                  Brand Name
                </label>
                <input
                  type="text"
                  value={editingBrand.name}
                  onChange={(e) =>
                    setEditingBrand({ ...editingBrand, name: e.target.value })
                  }
                  className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary"
                  placeholder="e.g., Apex Motors"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-foreground mb-2">
                  Logo (Emoji)
                </label>
                <input
                  type="text"
                  value={editingBrand.logo}
                  onChange={(e) =>
                    setEditingBrand({
                      ...editingBrand,
                      logo: e.target.value.slice(0, 2),
                    })
                  }
                  className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary text-2xl"
                  placeholder="🏛️"
                  maxLength={2}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-foreground mb-2">
                  Description
                </label>
                <textarea
                  value={editingBrand.description}
                  onChange={(e) =>
                    setEditingBrand({
                      ...editingBrand,
                      description: e.target.value,
                    })
                  }
                  className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary resize-none"
                  rows={3}
                  placeholder="Brand description..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Founded Year
                  </label>
                  <input
                    type="number"
                    value={editingBrand.founded}
                    onChange={(e) =>
                      setEditingBrand({
                        ...editingBrand,
                        founded: parseInt(e.target.value),
                      })
                    }
                    className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Country
                  </label>
                  <input
                    type="text"
                    value={editingBrand.country}
                    onChange={(e) =>
                      setEditingBrand({ ...editingBrand, country: e.target.value })
                    }
                    className="w-full px-4 py-2 rounded-lg border border-border bg-card focus:outline-none focus:ring-2 focus:ring-primary"
                    placeholder="e.g., USA"
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-3 justify-end">
              <Button
                variant="outline"
                onClick={() => {
                  setIsModalOpen(false);
                  setEditingBrand(null);
                }}
              >
                Cancel
              </Button>
              <Button onClick={handleSaveBrand} className="flex items-center gap-2">
                <Check className="w-4 h-4" />
                Save Brand
              </Button>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
}
